import androidx.appcompat.app.AppCompatActivity
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Log
import android.widget.Toast

class MainActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        val intent = intent
        if (Intent.ACTION_SEND == intent?.action && intent.getType() != null) {
            val uri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
            when (intent.type) {
                "text/plain" -> {
                    val text = intent.getStringExtra(Intent.EXTRA_TEXT)
                    Log.d("Shared Content", text ?: "")
                    Toast.makeText(this, text, Toast.LENGTH_SHORT).show()
                }
                "image/*" -> {
                    val imageUrl = uri?.toString()
                    Log.d("Shared Image URL", imageUrl ?: "")
                    // Handle the image as needed (e.g., display, save)
                }
                else -> Toast.makeText(this, "Unsupported data type", Toast.LENGTH_SHORT).show()
            }
        }
    }
}